import{_ as a,o as i,c as s,a2 as t}from"./chunks/framework.CpXckY1Z.js";const u=JSON.parse('{"title":"Installation","description":"","frontmatter":{},"headers":[],"relativePath":"guide/installation.md","filePath":"guide/installation.md","lastUpdated":1784533055000}'),n={name:"guide/installation.md"};function l(r,e,o,p,d,h){return i(),s("div",null,[...e[0]||(e[0]=[t('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>All packages are published independently — install only what your side of the wire needs. <code>@rapiq/core</code> is a peer dependency of every other package, so it is always part of the mix.</p><h2 id="caller-client-side" tabindex="-1">Caller (client) side <a class="header-anchor" href="#caller-client-side" aria-label="Permalink to &quot;Caller (client) side&quot;">​</a></h2><p>To build typed queries and encode them as URL query strings:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/core</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/codec-url</span></span></code></pre></div><p>That&#39;s everything a frontend needs. If you only build queries and hand them to an in-process consumer (no URL), <code>@rapiq/core</code> alone is enough.</p><h2 id="receiver-server-side" tabindex="-1">Receiver (server) side <a class="header-anchor" href="#receiver-server-side" aria-label="Permalink to &quot;Receiver (server) side&quot;">​</a></h2><p>To decode and validate incoming URL query input — a raw query string or a pre-parsed object like express&#39; <code>req.query</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/core</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/codec-url</span></span></code></pre></div><p>Then add the backend that executes queries against your data:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-KubTb" id="tab-SZfN0pD" checked><label data-title="TypeORM" for="tab-SZfN0pD">TypeORM</label><input type="radio" name="group-KubTb" id="tab-1vG0Nun"><label data-title="Raw SQL" for="tab-1vG0Nun">Raw SQL</label><input type="radio" name="group-KubTb" id="tab-2Pl06wR"><label data-title="In-memory" for="tab-2Pl06wR">In-memory</label></div><div class="blocks"><div class="language-sh vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/sql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/typeorm</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/sql</span></span></code></pre></div><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @rapiq/memory</span></span></code></pre></div></div></div><h2 id="optional-packages" tabindex="-1">Optional packages <a class="header-anchor" href="#optional-packages" aria-label="Permalink to &quot;Optional packages&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Package</th><th>Install when…</th></tr></thead><tbody><tr><td><a href="/packages/parser-simple.html">@rapiq/parser-simple</a></td><td>non-URL input already uses canonical parameter keys (<code>filters</code>, <code>pagination</code>, …)</td></tr><tr><td><a href="/packages/parser-expression.html">@rapiq/parser-expression</a></td><td>non-URL input contains function-call filter expressions like <code>and(eq(name, &#39;John&#39;), gte(age, &#39;18&#39;))</code></td></tr><tr><td><a href="/packages/parser-mongo.html">@rapiq/parser-mongo</a></td><td>you want to accept MongoDB-style filter documents like <code>{ age: { $gte: 18 } }</code></td></tr><tr><td><a href="/packages/memory.html">@rapiq/memory</a></td><td>you want to evaluate a <code>Query</code> against in-memory objects — e.g. authorization guards or mock backends</td></tr></tbody></table><p>Not sure which combination you need? The <a href="/packages/">package overview</a> walks through the decision.</p><h2 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h2><ul><li><strong>Node.js ≥ 22</strong> for the server-side packages; the client-side packages run in any modern bundler/browser environment.</li><li><strong>TypeScript</strong> is optional but strongly recommended — typed field paths are a core feature.</li></ul><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/guide/quick-start.html">Quick Start</a> — wire everything together in one walkthrough.</li></ul>',18)])])}const k=a(n,[["render",l]]);export{u as __pageData,k as default};
